    @constraint(model, E6346, SQR(X82) + 2*X82*X83 + SQR(X83) >= 0)
    @constraint(model, E6347, SQR(X82) - 2*X82*X84 + SQR(X84) >= 0)
    @constraint(model, E6348, SQR(X82) + 2*X82*X84 + SQR(X84) >= 0)
    @constraint(model, E6349, SQR(X82) - 2*X82*X85 + SQR(X85) >= 0)
    @constraint(model, E6350, SQR(X82) + 2*X82*X85 + SQR(X85) >= 0)
    @constraint(model, E6351, SQR(X82) - 2*X82*X86 + SQR(X86) >= 0)
    @constraint(model, E6352, SQR(X82) + 2*X82*X86 + SQR(X86) >= 0)
    @constraint(model, E6353, SQR(X82) - 2*X82*X108 + SQR(X108) >= 0)
    @constraint(model, E6354, SQR(X82) + 2*X82*X108 + SQR(X108) >= 0)
    @constraint(model, E6355, SQR(X83) - 2*X83*X84 + SQR(X84) >= 0)
    @constraint(model, E6356, SQR(X83) + 2*X83*X84 + SQR(X84) >= 0)
    @constraint(model, E6357, SQR(X83) - 2*X83*X85 + SQR(X85) >= 0)
    @constraint(model, E6358, SQR(X83) + 2*X83*X85 + SQR(X85) >= 0)
    @constraint(model, E6359, SQR(X83) - 2*X83*X86 + SQR(X86) >= 0)
    @constraint(model, E6360, SQR(X83) + 2*X83*X86 + SQR(X86) >= 0)
    @constraint(model, E6361, SQR(X84) - 2*X84*X85 + SQR(X85) >= 0)
    @constraint(model, E6362, SQR(X84) + 2*X84*X85 + SQR(X85) >= 0)
    @constraint(model, E6363, SQR(X84) - 2*X84*X86 + SQR(X86) >= 0)
    @constraint(model, E6364, SQR(X84) + 2*X84*X86 + SQR(X86) >= 0)
    @constraint(model, E6365, SQR(X84) - 2*X84*X108 + SQR(X108) >= 0)
    @constraint(model, E6366, SQR(X84) + 2*X84*X108 + SQR(X108) >= 0)
    @constraint(model, E6367, SQR(X85) - 2*X85*X86 + SQR(X86) >= 0)
    @constraint(model, E6368, SQR(X85) + 2*X85*X86 + SQR(X86) >= 0)
    @constraint(model, E6369, SQR(X85) - 2*X85*X108 + SQR(X108) >= 0)
    @constraint(model, E6370, SQR(X85) + 2*X85*X108 + SQR(X108) >= 0)
    @constraint(model, E6371, objvar == X0)
    @objective(model, Min, objvar)
    optimize!(model)
    return model
end
